28	/**
29	 * Adapts an OpenAI Codex CLI session "rollout" file into the step schema the frontend timeline
30	 * already understands (the same shape produced for Antigravity transcripts).
31	 *
32	 * <p>Each rollout line is {@code {type, timestamp, payload}}. The conversation is carried by
33	 * {@code response_item} lines (OpenAI Responses-API items): {@code message} (user/assistant),
34	 * {@code function_call}, {@code function_call_output}, and {@code reasoning}. Other line types
35	 * ({@code session_meta}, {@code turn_context}, {@code event_msg}) are not part of the rendered
36	 * timeline, though {@code event_msg/user_message} is used to derive a clean session title.
37	 */
38	final class CodexAdapter {
39	
40	    private CodexAdapter() {}
41	
42	    private static final ObjectMapper MAPPER = new ObjectMapper();
43	    // Anchored to line start (multiline) so command output that merely echoes the phrase doesn't
44	    // get misread as a failure. Detection is a heuristic on Codex's exec-output framing.
45	    private static final Pattern EXIT_CODE = Pattern.compile(
46	        "(?m)^Process exited with code (\\d+)"
47	    );
48	
49	    /**
50	     * Converts rollout lines into a JSON array string of timeline steps.
51	     *
52	     * @param lines the raw JSONL lines of a Codex rollout file
53	     * @return a JSON array (as a string) of step objects
54	     */
55	    static String toTranscriptJson(List<String> lines) {
56	        try {
57	            return MAPPER.writeValueAsString(toSteps(lines));
58	        } catch (Exception e) {
59	            return "[]";
60	        }
61	    }
62	
63	    static List<ObjectNode> toSteps(List<String> lines) {
64	        List<ObjectNode> steps = new ArrayList<>();
65	        for (String line : lines) {
66	            if (line == null || line.isBlank()) continue;
67	            try {
68	                JsonNode root = MAPPER.readTree(line);
69	                if (!"response_item".equals(root.path("type").asText(""))) continue;
70	
71	                String ts = root.path("timestamp").asText("");
72	                JsonNode payload = root.path("payload");
73	                ObjectNode step = stepFor(payload, ts);
74	                if (step != null) steps.add(step);
75	            } catch (Exception e) {
76	                // skip malformed lines
77	            }
78	        }
79	        return steps;
80	    }
81	
82	    private static ObjectNode stepFor(JsonNode payload, String ts) {
83	        String payloadType = payload.path("type").asText("");
84	        switch (payloadType) {
85	            case "message":
86	                return messageStep(payload, ts);
87	            case "function_call":
88	                return functionCallStep(payload, ts);
89	            case "function_call_output":
90	                return functionOutputStep(payload, ts);
91	            case "reasoning":
92	                return reasoningStep(payload, ts);
93	            default:
94	                return null;
95	        }
96	    }
97	
98	    private static ObjectNode messageStep(JsonNode payload, String ts) {
99	        String role = payload.path("role").asText("");
100	        String text = joinTextParts(payload.path("content"));
101	        if (text.isBlank()) return null;
102	        ObjectNode step = newStep(ts);
103	        if ("user".equals(role)) {
104	            step.put("type", "USER_INPUT");
105	            step.put("source", "USER_EXPLICIT");
106	        } else {
107	            step.put("type", "MESSAGE");
108	            step.put("source", "MODEL");
109	        }
110	        step.put("content", text);
111	        return step;
112	    }
113	
114	    private static ObjectNode functionCallStep(JsonNode payload, String ts) {
115	        ObjectNode step = newStep(ts);
116	        step.put("type", "FUNCTION_CALL");
117	        step.put("source", "MODEL");
118	        ArrayNode toolCalls = step.putArray("tool_calls");
119	        ObjectNode tool = toolCalls.addObject();
120	        tool.put("name", payload.path("name").asText("unknown"));
121	        tool.set("args", parseArguments(payload.path("arguments").asText("")));
122	        return step;
123	    }
