125	    private static ObjectNode functionOutputStep(JsonNode payload, String ts) {
126	        String output = outputText(payload.path("output"));
127	        if (output.isBlank()) return null;
128	        ObjectNode step = newStep(ts);
129	        step.put("type", "FUNCTION_OUTPUT");
130	        step.put("source", "TOOL");
131	        step.put("content", output);
132	        if (isFailure(output)) {
133	            step.put("status", "ERROR");
134	        }
135	        return step;
136	    }
